cpl([List|T], R) -> cpl(List, [T|R]);
cpl([], R) -> cp(R);
cpl(<<C/utf8, T/binary>>, R) -> [C,T|R];
cpl(<<>>, R) -> cp(R);
cpl(<<B/binary>>, R) -> {error,[B|R]}.

