-spec gc(String::unicode:chardata()) -> maybe_improper_list() | {error, unicode:chardata()}.
gc([]=R) -> R;
gc([CP]=R) when ?IS_CP(CP) -> R;
gc([$\r=CP|R0]) ->
    case cp(R0) of % Don't break CRLF
        [$\n|R1] -> [[$\r,$\n]|R1];
        T -> [CP|T]
    end;
gc([CP1|T1]=T) when ?IS_LATIN1(CP1) ->
    case T1 of
        [CP2|_] when ?IS_LATIN1(CP2) -> T; %% Ascii Fast path
        _ -> %% Keep the tail binary.
            case cp_no_bin(T1) of
                [CP2|_]=T3 when ?IS_LATIN1(CP2) -> [CP1|T3]; %% Asciii Fast path
                binary_found -> gc_1(T1, CP1);
                T4 -> gc_1(T4, CP1)
            end
    end;
gc(<<>>) -> [];
gc(<<CP1/utf8, Rest/binary>>) ->
    if CP1 < 256, CP1 =/= $\r ->
           case Rest of
               <<CP2/utf8, _/binary>> when CP2 < 256 -> %% Ascii Fast path
                   [CP1|Rest];
               _ -> gc_1(Rest, CP1)
           end;
      true -> gc_1(Rest, CP1)
    end;
gc([CP|T]) when ?IS_CP(CP) -> gc_1(T,CP);
gc(Str) ->
    case cp(Str) of
        {error,_}=Error -> Error;
        CPs -> gc(CPs)
    end.

