%% default clauses
gc_1(R,CP) ->
    case is_ext_pict(CP) of
        true -> gc_ext_pict(R, [CP]);
        false ->
            case is_indic_consonant(CP) of
                true -> gc_indic(cp(R), R, false, [CP]);
                false -> gc_extend(cp(R), R, CP)
            end
    end.

%% Handle Prepend
gc_prepend(R00, CP0) ->
    case cp(R00) of
      [CP1|R0] ->
          case is_control(CP1) of
            true -> [CP0|R00];
            false ->
                case gc_1(R0, CP1) of
                    [GC|R1] when is_integer(GC) -> [[CP0,GC]|R1];
                    [GC|R1] -> [[CP0|GC]|R1]
                end
           end;
      [] -> [CP0];
      {error,R} -> [CP0|R]
    end.

