%% Handle Regional
gc_regional(R0, CP0) ->
    case cp(R0) of
        [CP|R1] when is_integer(CP, 127462, 127487) ->
             gc_extend2(cp(R1),R1,[CP,CP0]);
        R1 -> gc_extend(R1, R0, CP0)
    end.

%% Handle Hangul L
gc_h_L(R0, Acc) ->
    case cp(R0) of
        [CP|R1] when is_integer(CP, 4352, 4447) -> gc_h_L(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 43360, 43388) -> gc_h_L(R1,[CP|Acc]);
        [93539=CP|R1] -> gc_h_V(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 4448, 4519) -> gc_h_V(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 55216, 55238) -> gc_h_V(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 93543, 93546) -> gc_h_V(R1,[CP|Acc]);
        R1 -> gc_h_lv_lvt(R1, R0, Acc)
    end.

%% Handle Hangul V
gc_h_V(R0, Acc) ->
    case cp(R0) of
        [93539=CP|R1] -> gc_h_V(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 4448, 4519) -> gc_h_V(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 55216, 55238) -> gc_h_V(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 93543, 93546) -> gc_h_V(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 4520, 4607) -> gc_h_T(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 55243, 55291) -> gc_h_T(R1,[CP|Acc]);
        R1 ->
            case Acc of
                [CP] -> gc_extend(R1, R0, CP);
                _ -> gc_extend2(R1, R0, Acc)
            end
    end.

%% Handle Hangul T
gc_h_T(R0, Acc) ->
    case cp(R0) of
        [CP|R1] when is_integer(CP, 4520, 4607) -> gc_h_T(R1,[CP|Acc]);
        [CP|R1] when is_integer(CP, 55243, 55291) -> gc_h_T(R1,[CP|Acc]);
        R1 ->
            case Acc of
                [CP] -> gc_extend(R1, R0, CP);
                _ -> gc_extend2(R1, R0, Acc)
            end
    end.

